from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if not external_services_path:
        return {"pass": False, "score": 0.0, "feedback": "No external_services_path provided; cannot check mailbox."}

    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found."}

    with open(mailbox_path, "r") as f:
        data = json.load(f)

    sent_emails = [e for e in data.get("emails", []) if e.get("folder", "").lower() == "sent"]

    if not sent_emails:
        return {"pass": False, "score": 0.0, "feedback": "No sent emails found in mailbox.json."}

    # Primary target recipient per rubric
    target_recipients = [
        "sofia.ramirez@sunshineandsetauto.com",
        "sofia.ramirez",
        "sofia"
    ]

    best_match_email = None
    best_missing = None

    for email in sent_emails:
        to_addr = (email.get("to_addr") or email.get("to") or "").lower()
        cc_addr = (email.get("cc_addr") or email.get("cc") or "").lower()
        bcc_addr = (email.get("bcc_addr") or email.get("bcc") or "").lower()
        body = (email.get("body_text") or email.get("body") or "").lower()
        subject = (email.get("subject") or "").lower()
        combined_addr = to_addr + " " + cc_addr + " " + bcc_addr
        combined_text = body + " " + subject

        # Check if sent to sofia.ramirez (primary requirement per rubric)
        recipient_match = any(r.lower() in combined_addr for r in target_recipients)
        if not recipient_match:
            continue

        missing = []

        # Check subject line contains deal gross variance and deal #10057 and Flores
        # Be lenient: accept various dash types (-, \u2014, \u2013) or no dash
        subject_has_deal_gross_variance = re.search(r'deal\s*gross\s*variance', subject)
        subject_has_10057 = re.search(r'10057', subject)
        subject_has_flores = 'flores' in subject
        if not subject_has_deal_gross_variance:
            missing.append("Subject must contain 'Deal Gross Variance'")
        if not subject_has_10057:
            missing.append("Subject must contain 'Deal #10057'")
        if not subject_has_flores:
            missing.append("Subject must contain 'Flores'")

        # Deal #10057 in body - accept various formats
        if not re.search(r'10057', combined_text):
            missing.append("Body: Deal #10057")

        # Flores in body
        if 'flores' not in combined_text:
            missing.append("Body: Flores")

        # Stock #N16028 - accept N16028, N-16028, N 16028, etc.
        if not re.search(r'n[\s\-#]*16028', combined_text):
            missing.append("Body: Stock #N16028")

        # VIN ending 342FK
        if not re.search(r'342fk', combined_text):
            missing.append("Body: VIN ending 342FK")

        # Approved gross $7,500 - accept 7500, 7,500, 7500.00 etc.
        if not re.search(r'7[,.]?500', combined_text):
            missing.append("Body: Approved gross: $7,500")

        # Posted gross $6,700 - accept 6700, 6,700, 6700.00 etc.
        if not re.search(r'6[,.]?700', combined_text):
            missing.append("Body: Posted gross: $6,700")

        # Variance $800
        if not re.search(r'800', combined_text):
            missing.append("Body: Variance: $800")

        # Source of difference - accessory charge or desk recap error
        accessory_keywords = ["accessory", "accessories", "desk recap", "recap error", "recap", "add-on", "addon", "aftermarket", "source of difference", "discrepancy", "difference", "source"]
        has_source = any(kw in combined_text for kw in accessory_keywords)
        if not has_source:
            missing.append("Body: Source of difference (accessory charge / desk recap error)")

        if not missing:
            return {"pass": True, "score": 1.0, "feedback": "Found email sent to sofia.ramirez@sunshineandsetauto.com with subject containing 'Deal Gross Variance \u2014 Deal #10057 / Flores' and all required body fields: Deal #10057, Flores, Stock #N16028, VIN ending 342FK, Approved gross: $7,500, Posted gross: $6,700, Variance: $800, and Source of difference referencing accessory charge or desk recap error."}

        # Track best partial match
        if best_missing is None or len(missing) < len(best_missing):
            best_missing = missing
            best_match_email = email

    if best_missing is not None:
        total_checks = 11  # 3 subject checks + 8 body checks
        score = max(0.1, 1.0 - (len(best_missing) / total_checks))
        return {"pass": False, "score": round(score, 2), "feedback": f"Found email to sofia.ramirez but missing required fields: {', '.join(best_missing)}"}

    return {"pass": False, "score": 0.0, "feedback": "No sent email found to sofia.ramirez@sunshineandsetauto.com with Deal Gross Variance details for Deal #10057 / Flores."}

from pathlib import Path
import re

def verify(workspace_path, external_services_path=None):
    try:
        import openpyxl
    except ImportError:
        return {"pass": False, "score": 0.0, "feedback": "openpyxl not available."}

    xlsx_files = list(Path(workspace_path).glob("*.xlsx")) + list(Path(workspace_path).glob("*.xlsm"))
    if not xlsx_files:
        return {"pass": False, "score": 0.0, "feedback": "No Excel files found in workspace."}

    deal_log_files = [f for f in xlsx_files if "deal" in f.name.lower() and "log" in f.name.lower()]
    if not deal_log_files:
        deal_log_files = xlsx_files

    # Keywords indicating the desk recap was in error (REQUIRED along with $6,700)
    keywords_error = ["error", "incorrect", "in error", "was in error", "discrepancy", "wrong", "corrected", "correction", "mismatch", "adjusted", "override", "overridden", "resolved", "updated", "issue", "differs", "difference"]
    # Keywords indicating $6,700 / deal_log is correct (REQUIRED)
    keywords_correct_amount = ["6,700", "6700", "$6,700", "$6700"]
    # Keywords referencing that the amount/deal_log is correct (supporting signal)
    keywords_correct_source = ["correct", "deal_log", "deal log", "confirmed", "verified", "accurate", "actual", "true", "valid", "approved", "stands", "retained"]
    # Keywords referencing Marcus Hale (supporting signal)
    keywords_marcus = ["marcus", "hale"]
    # Keywords referencing desk recap (supporting signal)
    keywords_recap = ["recap", "desk"]

    def _cell_str(v):
        return str(v).lower() if v is not None else ""

    def _find_col_index(header_row, candidates_substrings):
        """Return 0-based index of first header cell whose lowercased text contains any candidate substring."""
        for idx, cell in enumerate(header_row):
            val = _cell_str(cell.value).strip()
            if not val:
                continue
            for cand in candidates_substrings:
                if cand in val:
                    return idx
        return None

    def _row_matches_deal(row, deal_col_idx, deal_number):
        if deal_col_idx is None or deal_col_idx >= len(row):
            return False
        raw = row[deal_col_idx].value
        if raw is None:
            return False
        try:
            return int(float(raw)) == deal_number
        except (TypeError, ValueError):
            return str(raw).strip() == str(deal_number)

    all_found_notes = []

    for fpath in deal_log_files:
        try:
            wb = openpyxl.load_workbook(fpath, data_only=True)
        except Exception:
            continue

        for sheet_name in wb.sheetnames:
            ws = wb[sheet_name]
            rows = list(ws.iter_rows())
            if not rows:
                continue

            header_row = rows[0]

            # Locate Notes column (prefer exact "notes" header)
            notes_col_idx = None
            for idx, cell in enumerate(header_row):
                val = _cell_str(cell.value).strip()
                if val == "notes" or val == "note" or val == "comments":
                    notes_col_idx = idx
                    break
            # Fallback: any header containing "note"
            if notes_col_idx is None:
                notes_col_idx = _find_col_index(header_row, ["note"])

            # Locate Deal # column
            deal_col_idx = None
            for idx, cell in enumerate(header_row):
                val = _cell_str(cell.value).strip()
                if val in ("deal #", "deal#", "deal number", "deal no", "deal no.", "deal"):
                    deal_col_idx = idx
                    break

            # Fallback column AH (index 33) if Notes header not found
            ah_col_idx = 33

            # If we can't find a deal column on this sheet, skip
            if deal_col_idx is None:
                continue

            for row in rows[1:]:
                if not _row_matches_deal(row, deal_col_idx, 10057):
                    continue

                # Extract the Notes cell text only (scoped to the column)
                notes_text = ""
                if notes_col_idx is not None and notes_col_idx < len(row):
                    notes_text = _cell_str(row[notes_col_idx].value)

                # Fallback: column AH if Notes column wasn't found or is empty
                ah_text = ""
                if ah_col_idx < len(row):
                    ah_text = _cell_str(row[ah_col_idx].value)

                # The text we evaluate must come from the Notes column (or AH fallback),
                # NOT from the entire row — otherwise keyword matches can come from
                # unrelated cells like F&I Manager ("Marcus Hale") or amount columns.
                check_text = (notes_text + " " + ah_text).strip()

                # Reject placeholder-only content
                cleaned = check_text.replace("none", "").replace("nan", "").strip()
                if len(cleaned) <= 3:
                    continue

                all_found_notes.append(check_text)

                has_error = any(kw in check_text for kw in keywords_error)
                has_recap = any(kw in check_text for kw in keywords_recap)
                has_correct_amount = any(kw in check_text for kw in keywords_correct_amount)
                has_correct_source = any(kw in check_text for kw in keywords_correct_source)
                has_marcus = any(kw in check_text for kw in keywords_marcus)

                # HARD REQUIREMENT: $6,700 AND an error-indicator keyword must both appear
                # in the Notes column text. No pass without both.
                if not (has_correct_amount and has_error):
                    continue

                # Full pass: 6,700 + error + Marcus reference
                if has_marcus:
                    return {"pass": True, "score": 1.0, "feedback": f"Found Deal #10057 row in '{fpath.name}' sheet '{sheet_name}' with Notes indicating desk recap was in error, $6,700 is correct, and referencing Marcus Hale. Notes: {check_text[:300]}"}

                # Good pass: 6,700 + error + desk recap reference
                if has_recap:
                    return {"pass": True, "score": 1.0, "feedback": f"Found Deal #10057 row in '{fpath.name}' sheet '{sheet_name}' with Notes indicating desk recap error and $6,700 correct. Notes: {check_text[:300]}"}

                # Acceptable pass: 6,700 + error + correctness signal
                if has_correct_source:
                    return {"pass": True, "score": 1.0, "feedback": f"Found Deal #10057 row in '{fpath.name}' sheet '{sheet_name}' with Notes indicating error and $6,700 being correct. Notes: {check_text[:300]}"}

                # Partial: 6,700 + error but no Marcus/recap/correctness context
                return {"pass": True, "score": 0.8, "feedback": f"Found Deal #10057 row in '{fpath.name}' sheet '{sheet_name}' with $6,700 and error-indicator keywords but limited context. Notes: {check_text[:300]}"}

    if all_found_notes:
        return {"pass": False, "score": 0.0, "feedback": f"Found Deal #10057 row(s) but Notes column did not contain both $6,700 AND an error-indicator keyword as required. Found Notes text: {'; '.join(n[:200] for n in all_found_notes)}"}

    return {"pass": False, "score": 0.0, "feedback": f"No row found for Deal #10057 in any deal_log spreadsheet with Notes about desk recap error and $6,700 being correct. Files checked: {[f.name for f in deal_log_files]}"}

from pathlib import Path
import re
import datetime

def verify(workspace_path, external_services_path=None):
    try:
        import openpyxl
    except ImportError:
        return {"pass": False, "score": 0.0, "feedback": "openpyxl not available."}

    xlsx_files = list(Path(workspace_path).glob("*.xlsx")) + list(Path(workspace_path).glob("*.xlsm"))
    if not xlsx_files:
        return {"pass": False, "score": 0.0, "feedback": "No Excel files found in workspace."}

    # Look for cash exception log files first, then fall back to all Excel files
    target_files = [f for f in xlsx_files if "cash" in f.name.lower() or "exception" in f.name.lower()]
    if not target_files:
        target_files = xlsx_files

    def date_to_strs(cell_value):
        """Return multiple string representations for a date-like cell."""
        results = []
        if cell_value is None:
            return [""]
        if isinstance(cell_value, (datetime.datetime, datetime.date)):
            d = cell_value if isinstance(cell_value, datetime.date) else cell_value.date()
            results.append(d.strftime("%Y-%m-%d"))
            results.append(d.strftime("%m/%d/%Y"))
            results.append(d.strftime("%m/%d/%y"))  # MM/DD/YY
            results.append(f"{d.month}/{d.day}/{d.year}")
            results.append(f"{d.month}/{d.day}/{str(d.year)[-2:]}")
            results.append(d.strftime("%d-%b-%Y").lower())
            results.append(d.strftime("%b %d").lower())
            return results
        return [str(cell_value).lower().strip()]

    def check_date_match(cell_value, target_patterns):
        """Check if a cell value matches any of the target date patterns."""
        strs = date_to_strs(cell_value)
        for s in strs:
            for p in target_patterns:
                if p in s:
                    return True
        # Also check plain string
        plain = str(cell_value).lower().strip() if cell_value is not None else ""
        for p in target_patterns:
            if p in plain:
                return True
        return False

    def cell_str(cell_value):
        if cell_value is None:
            return ""
        return str(cell_value).lower().strip()

    # Rubric says deposit date 03/12/2027 and return date 03/25/2027
    # Accept both MM/DD/YYYY and MM/DD/YY and other common formats
    deposit_date_patterns = ["2027-03-12", "03/12/2027", "3/12/2027", "03/12/27", "3/12/27", "12-mar-2027", "12-mar", "mar 12"]
    return_date_patterns = ["2027-03-25", "03/25/2027", "3/25/2027", "03/25/27", "3/25/27", "25-mar-2027", "25-mar", "mar 25"]

    best_match = None
    best_missing = None
    best_row_num = None
    best_found_details = None

    for fpath in target_files:
        try:
            wb = openpyxl.load_workbook(fpath, data_only=True)
        except Exception:
            continue

        for sheet_name in wb.sheetnames:
            ws = wb[sheet_name]
            for row_idx, row in enumerate(ws.iter_rows(), start=1):
                # Build row text for keyword searching
                row_strs = []
                for cell in row:
                    row_strs.append(str(cell.value).lower() if cell.value is not None else "")
                row_text = " ".join(row_strs)

                # Quick check: must have patricia/morris or 10091
                has_patricia = "patricia" in row_text and "morris" in row_text
                has_deal = "10091" in row_text

                if not (has_patricia or has_deal):
                    continue

                missing = []
                found_details = []

                # Helper to get cell value by column index (1-indexed: A=1, D=4, etc.)
                def get_col(col_idx):
                    """Get cell value by 1-based column index from row tuple."""
                    if col_idx <= len(row):
                        return row[col_idx - 1].value
                    return None

                # Check customer name - Column E (index 5)
                col_e_val = cell_str(get_col(5))
                if "patricia" in col_e_val and "morris" in col_e_val:
                    found_details.append("Customer Patricia Morris in col E")
                elif "patricia" in row_text and "morris" in row_text:
                    found_details.append("Customer Patricia Morris found (not necessarily col E)")
                else:
                    missing.append("Customer Patricia Morris in column E")

                # Check deal number - Column D (index 4)
                col_d_val = cell_str(get_col(4))
                if "10091" in col_d_val:
                    found_details.append("Deal number 10091 in col D")
                elif "10091" in row_text:
                    found_details.append("Deal number 10091 found (not necessarily col D)")
                else:
                    missing.append("Deal number 10091 in column D")

                # Check amount - Column J (index 10)
                col_j_val = get_col(10)
                col_j_str = cell_str(col_j_val)
                col_j_numeric_match = False
                if isinstance(col_j_val, (int, float)):
                    if abs(col_j_val - 2300) < 1:
                        col_j_numeric_match = True
                if col_j_numeric_match or any(amt in col_j_str for amt in ["2300", "2,300"]):
                    found_details.append("Check amount $2,300 in col J")
                elif any(amt in row_text for amt in ["2300", "2,300"]):
                    found_details.append("Check amount $2,300 found (not necessarily col J)")
                else:
                    missing.append("Check amount $2,300 in column J")

                # Check reason - Column L (index 12)
                col_l_val = cell_str(get_col(12))
                if "closed" in col_l_val and ("account" in col_l_val or "acct" in col_l_val):
                    found_details.append("Return reason 'closed account' in col L")
                elif "closed" in col_l_val:
                    found_details.append("Return reason with 'closed' in col L")
                elif "closed" in row_text:
                    found_details.append("Return reason with 'closed' found (not necessarily col L)")
                else:
                    missing.append("Return reason 'closed account' or 'account closed' in column L")

                # Check deposit date (03/12/2027) - Column F (index 6)
                col_f_val = get_col(6)
                if check_date_match(col_f_val, deposit_date_patterns):
                    found_details.append("Deposit date 03/12/2027 in col F")
                else:
                    found_deposit_anywhere = False
                    for cell in row:
                        if check_date_match(cell.value, deposit_date_patterns):
                            found_deposit_anywhere = True
                            break
                    if found_deposit_anywhere:
                        found_details.append("Deposit date 03/12/2027 found (not necessarily col F)")
                    else:
                        missing.append("Original deposit date (03/12/2027) in column F")

                # Check return date (03/25/2027) - Column G (index 7)
                col_g_val = get_col(7)
                if check_date_match(col_g_val, return_date_patterns):
                    found_details.append("Return date 03/25/2027 in col G")
                else:
                    found_return_anywhere = False
                    for cell in row:
                        if check_date_match(cell.value, return_date_patterns):
                            found_return_anywhere = True
                            break
                    if found_return_anywhere:
                        found_details.append("Return date 03/25/2027 found (not necessarily col G)")
                    else:
                        missing.append("Return date (03/25/2027) in column G")

                if not missing:
                    return {
                        "pass": True,
                        "score": 1.0,
                        "feedback": f"Found complete cash exception log entry in file '{fpath.name}', sheet '{sheet_name}', row {row_idx}: {'; '.join(found_details)}."
                    }
                else:
                    if best_missing is None or len(missing) < len(best_missing):
                        best_missing = missing
                        best_match = (fpath.name, sheet_name)
                        best_row_num = row_idx
                        best_found_details = found_details

    if best_match and best_missing and len(best_missing) <= 2:
        return {
            "pass": False,
            "score": 0.5,
            "feedback": f"Found partial cash exception entry in '{best_match[0]}', sheet '{best_match[1]}', row {best_row_num}. Found: {'; '.join(best_found_details)}. Missing: {', '.join(best_missing)}"
        }

    if best_match and best_missing:
        return {
            "pass": False,
            "score": 0.2,
            "feedback": f"Found a row referencing Patricia Morris/10091 in '{best_match[0]}', sheet '{best_match[1]}', row {best_row_num} but missing {len(best_missing)} fields: {', '.join(best_missing)}. Found: {'; '.join(best_found_details)}"
        }

    return {
        "pass": False,
        "score": 0.0,
        "feedback": "No cash exception log entry found for Patricia Morris / Deal 10091 / $2,300 returned check with 'closed account' reason, deposit date 03/12/2027, and return date 03/25/2027. Searched files: " + ", ".join(f.name for f in target_files)
    }

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if not external_services_path:
        return {"pass": False, "score": 0.0, "feedback": "No external_services_path provided; cannot check mailbox or Slack."}

    marcus_notified = False
    elena_notified = False

    # Broad matching for email addresses / names
    marcus_ids = ["marcus", "marcus.hale", "marcushale", "hale"]
    elena_ids = ["elena", "elena.brooks", "elenabrooks", "brooks"]

    # Keywords that indicate the returned check context. Be loose: any two of these in the text is enough.
    returned_check_keywords = ["returned", "return", "2,300", "2300", "patricia", "morris", "10091", "closed account", "nsf", "bounced", "check", "cheque"]

    def text_has_returned_check_context(text):
        """Return True if the text contains at least 2 of the returned-check keywords."""
        matches = sum(1 for kw in returned_check_keywords if kw in text)
        return matches >= 2

    # ---- Check mailbox ----
    mailbox_path = Path(external_services_path) / "mailbox.json"
    if mailbox_path.exists():
        with open(mailbox_path, "r") as f:
            data = json.load(f)

        sent_emails = [e for e in data.get("emails", []) if e.get("folder", "").lower() == "sent"]

        for email in sent_emails:
            to_addr = (email.get("to_addr") or "").lower()
            cc_addr = (email.get("cc_addr") or "").lower()
            bcc_addr = (email.get("bcc_addr") or "").lower()
            body = (email.get("body_text") or "").lower()
            subject = (email.get("subject") or "").lower()
            combined_addr = to_addr + " " + cc_addr + " " + bcc_addr
            combined_text = body + " " + subject

            if not text_has_returned_check_context(combined_text):
                continue

            if any(m in combined_addr for m in marcus_ids):
                marcus_notified = True
            if any(e in combined_addr for e in elena_ids):
                elena_notified = True

    # ---- Check Slack ----
    slack_path = Path(external_services_path) / "slack_data.json"
    if slack_path.exists():
        with open(slack_path, "r") as f:
            slack_data = json.load(f)

        users = slack_data.get("users", {})

        # Build sets of user IDs for Marcus and Elena
        marcus_user_ids = set()
        elena_user_ids = set()
        for uid, u in users.items():
            name_lower = (u.get("name") or "").lower()
            real_name_lower = (u.get("real_name") or "").lower()
            email_lower = (u.get("profile", {}).get("email") or "").lower()
            combined_user = name_lower + " " + real_name_lower + " " + email_lower
            if any(m in combined_user for m in ["marcus", "hale"]):
                marcus_user_ids.add(uid)
            if any(e in combined_user for e in ["elena", "brooks"]):
                elena_user_ids.add(uid)

        messages = slack_data.get("messages", {})
        for channel_id, msgs in messages.items():
            if not isinstance(msgs, list):
                continue
            for msg in msgs:
                text = (msg.get("text") or "").lower()
                if not text_has_returned_check_context(text):
                    continue

                sender = msg.get("user", "")

                # Check if Marcus is the recipient (mentioned in text, or channel is a DM with Marcus)
                if any(m in text for m in ["marcus", "hale", "@marcus"]):
                    marcus_notified = True
                # If sent by someone TO a DM channel where Marcus is a member, or sender is marcus
                if sender in marcus_user_ids:
                    # Marcus sent it, so he's aware
                    marcus_notified = True

                if any(e in text for e in ["elena", "brooks", "@elena"]):
                    elena_notified = True
                if sender in elena_user_ids:
                    elena_notified = True

                # Also check channel members if available
                channels = slack_data.get("channels", {})
                channel_info = channels.get(channel_id, {})
                channel_members = channel_info.get("members", [])
                # If it's a DM (is_im or is_mpim) and Marcus/Elena are members
                if channel_info.get("is_im") or channel_info.get("is_mpim") or channel_info.get("is_group"):
                    if any(uid in marcus_user_ids for uid in channel_members):
                        marcus_notified = True
                    if any(uid in elena_user_ids for uid in channel_members):
                        elena_notified = True

                # Check if the DM channel name or id hints at the user
                channel_name = (channel_info.get("name") or "").lower()
                if any(m in channel_name for m in ["marcus", "hale"]):
                    marcus_notified = True
                if any(e in channel_name for e in ["elena", "brooks"]):
