    if not deal_log_files:
        deal_log_files = xlsx_files

    def parse_dollar(val):
        """Try to parse a cell value as a numeric dollar amount."""
        if val is None:
            return None
        if isinstance(val, (int, float)):
            return round(float(val), 2)
        s = str(val).strip().replace("$", "").replace(",", "").strip()
        try:
            return round(float(s), 2)
        except (ValueError, TypeError):
            return None

    for fpath in deal_log_files:
        try:
            wb = openpyxl.load_workbook(fpath, data_only=True)
        except Exception:
            continue

        # Look for a sheet that matches "Q1 2027" loosely
        target_sheet = None
        for sheet_name in wb.sheetnames:
            sn_lower = sheet_name.lower().replace(" ", "")
            if "q1" in sn_lower and "2027" in sn_lower:
                target_sheet = sheet_name
                break

        if target_sheet is None:
            sheets_to_check = wb.sheetnames
        else:
            sheets_to_check = [target_sheet]

        for sheet_name in sheets_to_check:
            ws = wb[sheet_name]

            # The rubric says row 27. First verify deal 10099 is there.
            row_num = 27

            row_has_10099 = False
            for cell in ws[row_num]:
                if cell.value is not None and "10099" in str(cell.value):
                    row_has_10099 = True
                    break

            if not row_has_10099:
                # Try to find 10099 in other rows of this sheet
                found_row = None
                for row in ws.iter_rows():
                    for cell in row:
                        if cell.value is not None and "10099" in str(cell.value):
                            found_row = cell.row
                            break
                    if found_row:
                        break
                if found_row:
                    row_num = found_row
                else:
                    continue

            # AC = column 29, AD = column 30, AE = column 31
            val_ac = ws.cell(row=row_num, column=29).value
            val_ad = ws.cell(row=row_num, column=30).value
            val_ae = ws.cell(row=row_num, column=31).value

            num_ac = parse_dollar(val_ac)
            num_ad = parse_dollar(val_ad)
            num_ae = parse_dollar(val_ae)

            issues = []
            passes = []

            # Check AC = $2,161 (tolerance ±1.5)
            if num_ac is not None and abs(num_ac - 2161.0) < 1.5:
                passes.append(f"AC{row_num} = ${num_ac} (expected $2,161) ✓")
            else:
                issues.append(f"AC{row_num} = {val_ac} (parsed: {num_ac}), expected $2,161")

            # Check AD = $6,059 (tolerance ±1.5)
            if num_ad is not None and abs(num_ad - 6059.0) < 1.5:
                passes.append(f"AD{row_num} = ${num_ad} (expected $6,059) ✓")
            else:
                issues.append(f"AD{row_num} = {val_ad} (parsed: {num_ad}), expected $6,059")

            # Check AE = $8,220 (tolerance ±1.5)
            if num_ae is not None and abs(num_ae - 8220.0) < 1.5:
                passes.append(f"AE{row_num} = ${num_ae} (expected $8,220) ✓")
            else:
                issues.append(f"AE{row_num} = {val_ae} (parsed: {num_ae}), expected $8,220")

            if not issues:
                return {
                    "pass": True,
                    "score": 1.0,
                    "feedback": f"Deal #10099 figures in sheet '{sheet_name}' of '{fpath.name}' are unchanged: {'; '.join(passes)}"
                }
            else:
                score = len(passes) / (len(passes) + len(issues))
                pass_result = score >= 1.0
                return {
                    "pass": pass_result,
                    "score": round(score, 2),
                    "feedback": f"Deal #10099 in sheet '{sheet_name}' of '{fpath.name}': PASSED: {passes}; ISSUES: {issues}"
                }

    return {"pass": True, "score": 0.8, "feedback": "Deal #10099 not found in any deal_log sheet - cannot verify figures were unchanged, but no alteration detected."}

